INSERT INTO node_properties (id, node_id, name, value_type, string_value, date_value, ref_node_id) VALUES
('d4000000-0003-0000-0000-000000000001', 'd4000000-0001-0000-0000-000000000001', 'description', 'STRING', 'La plus grande entreprise de divertissement au monde. Fondée par Walt Disney et Roy O. Disney en 1923. Valorisée à plus de 180 milliards de dollars', NULL, NULL),
('d4000000-0003-0000-0000-000000000002', 'd4000000-0001-0000-0000-000000000001', 'fondateurs', 'STRING', 'Walt Disney, Roy O. Disney', NULL, NULL),
('d4000000-0003-0000-0000-000000000003', 'd4000000-0001-0000-0000-000000000001', 'annee_creation', 'STRING', '1923', NULL, NULL),
('d4000000-0003-0000-0000-000000000004', 'd4000000-0001-0000-0000-000000000005', 'description', 'STRING', 'Studio d''animation fondé en 1986 par Steve Jobs après son rachat de Lucasfilm Graphics Group. Racheté par Disney en 2006 pour 7,4 milliards. Créateurs de Toy Story, Le Roi Lion, Coco', NULL, NULL),
('d4000000-0003-0000-0000-000000000005', 'd4000000-0001-0000-0000-000000000005', 'annee_rachat', 'STRING', '2006', NULL, NULL),
('d4000000-0003-0000-0000-000000000006', 'd4000000-0001-0000-0000-000000000005', 'prix_rachat', 'STRING', '7,4 milliards de dollars', NULL, NULL),
('d4000000-0003-0000-0000-000000000007', 'd4000000-0001-0000-0000-000000000006', 'description', 'STRING', 'Maison mère de Marvel Studios et Marvel Comics. Racheté par Disney en 2009 pour 4 milliards. A apporté Spider-Man, Iron Man, Captain America et l''univers MCU', NULL, NULL),
('d4000000-0003-0000-0000-000000000008', 'd4000000-0001-0000-0000-000000000006', 'annee_rachat', 'STRING', '2009', NULL, NULL),
('d4000000-0003-0000-0000-000000000009', 'd4000000-0001-0000-0000-000000000006', 'prix_rachat', 'STRING', '4 milliards de dollars', NULL, NULL),
('d4000000-0003-0000-0000-000000000010', 'd4000000-0001-0000-0000-000000000007', 'description', 'STRING', 'Studio fondé par George Lucas en 1971. Racheté par Disney en 2012 pour 4 milliards. Détenteur des franchises Star Wars et Indiana Jones', NULL, NULL),
('d4000000-0003-0000-0000-000000000011', 'd4000000-0001-0000-0000-000000000007', 'annee_rachat', 'STRING', '2012', NULL, NULL),
('d4000000-0003-0000-0000-000000000012', 'd4000000-0001-0000-0000-000000000007', 'prix_rachat', 'STRING', '4 milliards de dollars', NULL, NULL),
('d4000000-0003-0000-0000-000000000013', 'd4000000-0001-0000-0000-000000000008', 'description', 'STRING', 'Réseau de télévision américain fondé en 1943. Racheté par Disney en 1995 pour 19 milliards. L''une des plus grandes chaînes généralistes américaines', NULL, NULL),
('d4000000-0003-0000-0000-000000000014', 'd4000000-0001-0000-0000-000000000008', 'annee_rachat', 'STRING', '1995', NULL, NULL),
('d4000000-0003-0000-0000-000000000015', 'd4000000-0001-0000-0000-000000000009', 'description', 'STRING', 'Réseau sportif mondial lancé en 1979. Propriété de Disney depuis 1995. La chaîne sportive la plus regardée au monde avec droits NBA, NFL, MLB et plus', NULL, NULL),
('d4000000-0003-0000-0000-000000000016', 'd4000000-0001-0000-0000-000000000009', 'annee_rachat', 'STRING', '1995', NULL, NULL),
('d4000000-0003-0000-0000-000000000017', 'd4000000-0001-0000-0000-000000000010', 'description', 'STRING', 'Marque emblématique de documentaires et de science. Acquise via le rachat de 21st Century Fox en 2019. Présente dans 172 pays', NULL, NULL),
('d4000000-0003-0000-0000-000000000018', 'd4000000-0001-0000-0000-000000000010', 'annee_rachat', 'STRING', '2019', NULL, NULL),
('d4000000-0003-0000-0000-000000000019', 'd4000000-0001-0000-0000-000000000012', 'description', 'STRING', 'Service de streaming lancé en novembre 2019. A atteint 100 millions d''abonnés en 16 mois. Plateforme principale de diffusion du contenu Marvel, Star Wars et Disney', NULL, NULL),
('d4000000-0003-0000-0000-000000000020', 'd4000000-0001-0000-0000-000000000012', 'annee_lancement', 'STRING', '2019', NULL, NULL),
('d4000000-0003-0000-0000-000000000021', 'd4000000-0001-0000-0000-000000000019', 'description', 'STRING', 'Univers cinématographique interconnecté lancé en 2008 avec Iron Man. Série de films la plus rentable de l''histoire du cinéma avec plus de 29 milliards de dollars de recettes', NULL, NULL),
('d4000000-0003-0000-0000-000000000022', 'd4000000-0001-0000-0000-000000000019', 'annee_lancement', 'STRING', '2008', NULL, NULL),
('d4000000-0003-0000-0000-000000000023', 'd4000000-0001-0000-0000-000000000020', 'description', 'STRING', 'Actifs rachetés à 21st Century Fox en 2019 pour 71,3 milliards. A apporté National Geographic, FX, les droits de certains personnages Marvel (X-Men, Fantastic Four)', NULL, NULL),
('d4000000-0003-0000-0000-000000000024', 'd4000000-0001-0000-0000-000000000020', 'prix_rachat', 'STRING', '71,3 milliards de dollars', NULL, NULL);
